package main

import (
    "fmt"
    "runtime"
)

func main() {
    fmt.Printf("OS: %s\n", runtime.GOOS)
    fmt.Printf("Architecture: %s\n", runtime.GOARCH)
    fmt.Println("Hello, cross-compiled world!")
}

// ---- Build commands ----
// Basic build:
// go build
// go build -o myapp
// go build -ldflags "-s -w" -o myapp

// ---- Cross-compile ----
// Linux:
// GOOS=linux GOARCH=amd64 go build -o myapp-linux

// Windows:
// GOOS=windows GOARCH=amd64 go build -o myapp.exe

// macOS (Intel):
// GOOS=darwin GOARCH=amd64 go build -o myapp-mac

// macOS (Apple Silicon):
// GOOS=darwin GOARCH=arm64 go build -o myapp-mac-arm64

// ---- All platforms ----
// Windows:
// GOOS=windows GOARCH=386 go build -o myapp-windows-386.exe
// GOOS=windows GOARCH=amd64 go build -o myapp-windows-amd64.exe

// Linux:
// GOOS=linux GOARCH=386 go build -o myapp-linux-386
// GOOS=linux GOARCH=amd64 go build -o myapp-linux-amd64
// GOOS=linux GOARCH=arm go build -o myapp-linux-arm
// GOOS=linux GOARCH=arm64 go build -o myapp-linux-arm64

// macOS:
// GOOS=darwin GOARCH=amd64 go build -o myapp-darwin-amd64
// GOOS=darwin GOARCH=arm64 go build -o myapp-darwin-arm64

// ---- Build flags ----
// -ldflags "-s -w"    # Strip debug info (smaller binary)
// -ldflags "-X main.version=1.0.0"  # Inject version
// -o myapp            # Output name
// -v                  # Verbose
// -a                  # Force rebuild
// -tags netgo         # Build tags

